import { 運筆 } from '../bi.js';
import { 月輪, 頭光, 蓮華座, 菩薩開臉, 垂埵耳, 頸三道, 寶髻, 垂髮, 頸瓔, 胸瓔, 臂釧, 腕釧, 智拳印 as 智拳印部 } from '../bujian/index.js';
export const 大日金剛界 = (bi) => {
    const { A, E, dot, dim, W_OUT } = bi;
    const { M, L, C, Qk, S, 骨, 衣, 細, 逸 } = 運筆(bi);
    // ── 光：白月輪滿含全躯，頭光細雙環含冠 ────────────────────────────────────
    月輪(bi);
    頭光(bi);
    // ── 天衣：掛於兩肘而降，至座際翻飛外颺（図樣之勢），舌端有摺 ──────────────
    dim(0.65, () => 衣(() => {
        for (const d of [-1, 1]) {
            逸(() => {
                M(d * 14.75, 42.6);
                C(d * 17.7, 44.6, d * 18.3, 48.8, d * 17.8, 52.4);
                C(d * 17.4, 55.4, d * 18.0, 58.0, d * 17.35, 60.2);
                S();
                M(d * 15.9, 45.5);
                C(d * 16.5, 48.8, d * 16.3, 52.0, d * 16.7, 55.0);
                S();
            });
            // 翻飛之舌：出於趺坐之側
            M(d * 17.35, 60.2);
            C(d * 19.6, 58.6, d * 21.8, 57.9, d * 23.3, 58.8);
            Qk(d * 24.1, 59.5, d * 23.2, 60.6);
            C(d * 21.4, 62.0, d * 19.2, 62.1, d * 17.8, 61.5);
            S();
            細(() => { M(d * 19.5, 59.5); Qk(d * 20.9, 59.15, d * 22.1, 59.4); S(); });
        }
    }));
    // ── 座：仰蓮二重（部件） ──────────────────────────────────────────────────
    蓮華座(bi);
    // ── 趺坐之體：膝至膝五十二指（經之校驗律）；上緣於仰足處斷筆 ──────────────
    骨(() => {
        M(-25.9, 64.4);
        C(-25.4, 61.6, -22.0, 60.6, -17.5, 60.5);
        C(-11.0, 60.4, -6.0, 59.8, 0, 59.6);
        Qk(2.4, 59.7, 4.6, 59.9);
        S();
        M(14.2, 60.4);
        Qk(15.9, 60.45, 17.5, 60.5);
        C(22.0, 60.6, 25.4, 61.6, 25.9, 64.4);
        S();
        M(-25.9, 64.4);
        C(-25.0, 67.2, -17.0, 68.3, 0, 68.4);
        C(17.0, 68.3, 25.0, 67.2, 25.9, 64.4);
        S();
    });
    // ── 軀幹：頸→肩峰→臂。肩有峰、肘有轉、腕有節 ────────────────────────────
    骨(() => {
        // 頸柱
        M(-2.65, 20.9);
        Qk(-2.95, 22.6, -2.9, 24.1);
        S();
        M(2.65, 20.9);
        Qk(2.95, 22.6, 2.9, 24.1);
        S();
        // 僧帽肌之坡與三角肌之峰
        for (const d of [-1, 1]) {
            M(d * 2.9, 24.1);
            C(d * 5.8, 24.4, d * 9.2, 24.9, d * 11.4, 25.9);
            Qk(d * 12.8, 26.7, d * 13.2, 27.9);
            S();
        }
        // 上臂外緣→肘（尊右臂前臂上抱，尊左臂前臂內收）
        M(-13.2, 27.9);
        C(-14.2, 29.7, -14.5, 32.2, -14.3, 35.2);
        C(-14.1, 38.2, -14.6, 41.0, -14.7, 43.4);
        S();
        M(13.2, 27.9);
        C(14.2, 29.7, 14.5, 32.2, 14.3, 35.4);
        C(14.1, 38.4, 14.5, 42.2, 14.5, 44.6);
        S();
        // 前臂：尊右自肘上抱入上拳——端非徒貼，杆勢切入拳郭之弧（氣韻連貫之律）
        M(-14.7, 43.4);
        C(-12.2, 42.8, -8.4, 40.8, -6.2, 39.2);
        Qk(-4.4, 38.3, -2.6, 37.4);
        S();
        M(-13.4, 42.0);
        C(-10.4, 40.2, -7.6, 38.0, -6.0, 36.7);
        Qk(-4.4, 36.3, -2.65, 36.05);
        S();
        // 前臂：尊左自肘內收入下拳，杆勢順拳底之弧而沒
        M(14.5, 44.6);
        C(12.0, 45.6, 8.7, 45.4, 6.3, 45.0);
        Qk(4.3, 44.3, 1.8, 42.6);
        S();
        M(12.3, 42.6);
        C(10.1, 42.5, 8.1, 42.4, 6.5, 42.2);
        Qk(5.0, 42.0, 2.75, 41.75);
        S();
        // 軀幹之側：腋→腰之收→胯之張，入於趺坐
        M(-11.0, 32.4);
        C(-10.2, 36.5, -9.8, 40.5, -10.2, 46.5);
        Qk(-10.6, 50.0, -12.8, 53.0);
        S();
        M(11.0, 32.4);
        C(10.2, 36.5, 9.8, 40.5, 10.2, 46.5);
        Qk(10.6, 50.0, 12.8, 53.0);
        S();
    });
    // 胸腹之相：鎖骨微提、臍（菩薩白描胸腹尚簡，不施乳線）
    細(() => {
        M(-2.4, 25.7);
        Qk(-6.0, 26.3, -9.4, 25.9);
        S();
        M(2.4, 25.7);
        Qk(6.0, 26.3, 9.4, 25.9);
        S();
        M(0, 47.5);
        L(0, 48.4);
        S();
        A(0, 48.0, 0.4, Math.PI * 0.25, Math.PI * 0.75); // 臍
    });
    // ── 裙：束腰結帶，褶自腰而下有起伏，扇於兩股，聚於膝 ──────────────────────
    衣(() => {
        // 裙腰雙線
        M(-10.3, 50.4);
        Qk(0, 49.5, 10.3, 50.4);
        S();
        M(-10.5, 51.6);
        Qk(0, 50.7, 10.5, 51.6);
        S();
        // 結帶：左腰小結，帶尾雙垂
        A(-3.4, 51.1, 0.6);
        逸(() => {
            M(-3.2, 51.8);
            Qk(-3.8, 53.6, -3.0, 55.4);
            S();
            M(-3.7, 51.8);
            Qk(-4.7, 53.4, -4.4, 55.0);
            S();
            // 左股之褶：三線放射，弧墜有勢
            M(-5.4, 52.8);
            C(-9.0, 56.2, -15.0, 59.0, -21.2, 61.4);
            S();
            M(-4.5, 54.6);
            C(-7.5, 57.8, -12.0, 60.0, -17.0, 61.6);
            S();
            M(-6.4, 52.0);
            C(-12.0, 54.6, -18.5, 57.8, -23.6, 61.2);
            S();
            // 右股之褶：二線（餘為仰足所居）
            M(5.6, 52.6);
            C(9.8, 55.2, 15.6, 57.6, 21.4, 61.0);
            S();
            M(6.6, 51.9);
            C(12.4, 54.0, 18.8, 57.2, 23.8, 60.8);
            S();
            // 兩脛之間：懸褶三重，聚散有致
            M(-4.0, 55.8);
            Qk(0, 58.0, 4.0, 55.8);
            S();
            M(-5.2, 57.2);
            Qk(0, 59.6, 5.2, 57.2);
            S();
            M(-2.3, 57.0);
            Qk(0, 58.3, 2.3, 57.0);
            S();
            // 膝頭之褶：短弧各二
            M(-23.8, 63.2);
            Qk(-21.6, 62.4, -19.8, 63.0);
            S();
            M(-22.4, 65.6);
            Qk(-20.0, 64.6, -17.8, 65.2);
            S();
            M(23.8, 63.2);
            Qk(21.6, 62.4, 19.8, 63.0);
            S();
            M(22.4, 65.6);
            Qk(20.0, 64.6, 17.8, 65.2);
            S();
        });
    });
    // ── 仰足：右足安左股，足心向上（畫面右），逐趾有節，足心具輪 ──────────────
    衣(() => {
        // 踝橋：趺坐斷線之左端接於踵
        M(4.6, 59.9);
        Qk(5.3, 60.0, 5.8, 60.6);
        S();
        // 踵圓與足底兩緣（足在趺坐輪廓之前，其線於此斷開）
        A(6.5, 61.8, 1.2, Math.PI * 0.3, Math.PI * 1.85);
        M(6.3, 60.7);
        C(8.0, 60.0, 10.4, 59.8, 12.5, 60.3);
        S();
        M(7.2, 62.9);
        C(9.2, 62.9, 11.0, 62.5, 12.5, 62.1);
        S();
        細(() => {
            // 五趾：拇趾大而圓，餘趾以次而斂
            E(13.2, 60.7, 0.7, 0.56);
            A(13.4, 61.45, 0.4, Math.PI * 1.15, Math.PI * 0.85);
            A(13.25, 62.0, 0.37, Math.PI * 1.15, Math.PI * 0.85);
            A(12.95, 62.5, 0.34, Math.PI * 1.15, Math.PI * 0.85);
            A(12.5, 62.9, 0.31, Math.PI * 1.15, Math.PI * 0.85);
            // 千輻輪：足心之輪
            A(9.7, 61.4, 0.6);
            for (let i = 0; i < 6; i++) {
                const a = (Math.PI * 2 * i) / 6;
                M(9.7 + Math.cos(a) * 0.24, 61.4 + Math.sin(a) * 0.24);
                L(9.7 + Math.cos(a) * 0.52, 61.4 + Math.sin(a) * 0.52);
                S();
            }
        });
    });
    // ── 條帛：自尊左肩斜貫至右腰，沒於上拳之後，出於下拳之下 ─────────────────
    dim(0.75, () => 衣(() => 逸(() => {
        M(9.7, 26.3);
        C(7.8, 28.1, 6.0, 30.0, 3.9, 32.6);
        S();
        M(10.6, 27.2);
        C(8.8, 29.0, 7.0, 30.9, 4.9, 33.5);
        S();
        M(-3.8, 45.0);
        C(-5.9, 46.4, -8.3, 47.8, -9.7, 49.4);
        S();
        M(-2.9, 46.2);
        C(-4.9, 47.6, -7.1, 48.8, -8.5, 50.2);
        S();
        細(() => { M(6.7, 29.6); L(7.5, 30.4); S(); M(-5.9, 46.9); L(-5.2, 47.7); S(); });
    })));
    // ── 智拳印（部件歸一，2026-07-05）：掛手印庫之智拳印——右拳包左頭指，
    //    兩拳相合如一，惟尖微露拳頂、右拇端拄之；蔽法自治遮擋（飾=false 掛尊）────
    智拳印部(bi, 0, 38.8, 0.88, false);
    // ── 嚴（部件）：頸瓔貼頸，胸瓔垂珠讓開拳頂，臂釧鑲珠，腕釧順臂勢 ──────────
    頸瓔(bi);
    胸瓔(bi, { 滴z: 30.7 });
    臂釧(bi, -1);
    臂釧(bi, 1);
    腕釧(bi, [[-5.55, 35.9, -5.15, 37.0, -4.7, 38.3], [-4.75, 35.5, -4.35, 36.6, -3.95, 37.9]], [-4.85, 36.9]);
    腕釧(bi, [[4.35, 42.1, 4.75, 43.3, 4.4, 44.6], [5.25, 42.2, 5.65, 43.35, 5.3, 44.65]], [5.0, 43.4]);
    // ── 面（部件）：開臉・垂埵耳・頸三道 ─────────────────────────────────────
    菩薩開臉(bi);
    垂埵耳(bi);
    頸三道(bi);
    // ── 五智寶冠：帶綴珠，五峰各安寶板鑲珠，中峰最高；繒帶外颺（大日專相）────
    衣(() => {
        // 冠帶雙線（隨額之弧）
        M(-5.5, 8.9);
        Qk(0, 7.7, 5.5, 8.9);
        S();
        M(-5.35, 7.7);
        Qk(0, 6.5, 5.35, 7.7);
        S();
        細(() => { for (const [bx, bz] of [[-4.1, 8.0], [-2.05, 7.5], [0, 7.3], [2.05, 7.5], [4.1, 8.0]])
            dot(bx, bz, 0.22); });
        // 中峰寶板：法界體性智，最高
        M(-1.7, 6.4);
        C(-1.95, 4.9, -1.15, 3.3, 0, 2.3);
        C(1.15, 3.3, 1.95, 4.9, 1.7, 6.4);
        S();
        細(() => { A(0, 4.7, 0.65); dot(0, 4.7, 0.18); M(0, 2.3); L(0, 1.55); S(); });
        for (const d of [-1, 1]) {
            // 次峰寶板
            M(d * 2.1, 6.75);
            C(d * 2.0, 5.5, d * 2.4, 4.35, d * 3.15, 3.85);
            C(d * 3.9, 4.5, d * 4.2, 5.6, d * 4.05, 6.95);
            S();
            細(() => { A(d * 3.1, 5.4, 0.5); dot(d * 3.1, 5.4, 0.14); });
            // 外峰寶板（微傾向外）
            M(d * 4.5, 7.3);
            C(d * 4.45, 6.3, d * 4.85, 5.4, d * 5.5, 5.0);
            C(d * 6.2, 5.6, d * 6.45, 6.6, d * 6.25, 7.65);
            S();
            細(() => { A(d * 5.45, 6.35, 0.44); dot(d * 5.45, 6.35, 0.13); });
            // 繒帶：自冠側外颺，一線短而有折
            dim(0.7, () => 細(() => {
                M(d * 5.8, 8.6);
                C(d * 7.9, 9.3, d * 8.3, 10.9, d * 8.9, 12.4);
                Qk(d * 9.25, 13.3, d * 8.7, 13.9);
                S();
            }));
        }
    });
    // ── 髮（部件）：寶髻聳於冠上，鬢髮兩縷有波，拂肩而歇 ─────────────────────
    寶髻(bi);
    垂髮(bi);
};
